sp_css.css:
/*
Tasker Classification Ribbon and Badge
Used with <div class="taskform-classification-banner taskform-classification-banner-{{c.data.classification}}"> 
Used with <div class="badge taskform-classification-banner-{{c.data.classification}}"> looks like a pill
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  Put into a style sheet
2.8 | 2022-02-02 | mmcc | STRY0117772 - Tech Debt - Identify Style Sheets when viewed from browser Dev Tools
  Added .ClassificationBannerStyleSheet to name which style sheet this is when viewed from browser Dev Tools
2.8 | 2022-07-19 | mmcc | STRY0118268 - Stretch- Post Fixed Header+Action Bar for Modals- Clean up to display more content on screen 
Change Classification to be a ribbon 
2.8 | 2022-08-12 | mmccune | STRY0127100 - Existing Task Form- New Ribbon Colors for Classification
Added .taskform-classification-banner-Top.Secret.SCI, .taskform-classification-banner-Confidential,
.taskform-classification-banner-Controlled, .taskform-classification-banner-CUI and
.taskform-classification-banner-Controlled.Unclassified.Information

*/
.ClassificationBannerStyleSheet { display: none; } /* Name of Style Sheet, do not use to style HTML */


.taskform-classification-banner {
  font-size: smaller;
  text-align: center;
}

.taskform-classification-banner-Unclassified {
  background-color: $classification-unclassified-bg;
  color: $classification-unclassified-text;
}

.taskform-classification-banner-Controlled,
.taskform-classification-banner-CUI,
.taskform-classification-banner-Controlled.Unclassified.Information {
  background-color: $classification-controlled-bg;
  color: $classification-controlled-text;
}

.taskform-classification-banner-Official {
  background-color: $classification-official-bg; 
  color: $classification-official-text;
}

.taskform-classification-banner-Protected {
  /* 2.7.0 | 2021-08-07 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance */
  /* change color to a brown and add semicolon */
  /* background-color: #44835e */
  background-color: $classification-protected-bg;
  color: $classification-protected-text;
}

.taskform-classification-banner-Restricted {
  background-color: $classification-restricted-bg; 
  color: $classification-restricted-text;
}

.taskform-classification-banner-Confidential {
  background-color: $classification-confidential-bg;
  color: $classification-confidential-text;
}

.taskform-classification-banner-Secret {
  background-color: $classification-secret-bg;
  color: $classification-secret-text;
}

.taskform-classification-banner-Top.Secret {
  background-color: $classification-top-secret-bg;
  color: $classification-top-secret-text;
}

.taskform-classification-banner-Top.Secret.SCI {
background-color: $classification-top-secret-sci-bg;
color: $classification-top-secret-sci-text;
}
